VALUES
  ('social-worker-moex-07060', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '認同（identity）是青少年期重要的發展課題之一，有關認同的功能，下列敘述何者最適切？', '["提供一個架構，讓個體了解自己是誰；幫助個體同化於主流社會", "提供個體控制感與自由意志；透過承諾價值和目標，為個體提供意義和方向", "協助個體自我接納，和符合外在社會期望", "提供一個架構，讓個體了解自己是誰和符合外在社會期望"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07061', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關「壓迫」（oppression）的敘述中，下列何者錯誤？', '["壓迫通常具有結構性，它往往是社會制度安排所造成的後果", "種族主義、父權主義、性別主義都是屬於支持壓迫的意識形態", "壓迫往往基於刻板印象，它是一種主觀的意識形態", "底層階級（underclass）的形成，往往與壓迫密切相關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07062', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '學齡前的兒童若經常目睹父母親暴力相向，最可能導致幼兒產生下列那些狀況？①呈現身體症狀及消極', '["出現明顯分離焦慮", "智力嚴重受損", "覺得世界不安全", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07063', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '生命歷程觀點（life course perspective）的重要關注之一，乃人類發展的風險因子和保護因子，就其意涵而 言，下列何者正確：', '["每一生命的過渡期經驗歷程對下一生命事件會有所衝擊，且可能帶來生命軌跡上的危機或轉機", "人類發展需置於歷史脈絡及社會文化結構下來檢視，才能見出其風險因子和保護因子", "人類的生命歷程根植於歷史脈絡及社會文化結構中，並對其帶來優勢機會或劣勢及挑戰", "個人生命歷程的建構，有賴其對風險因子和保護因子的選擇與行動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07064', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關兒童對於族群認同的敘述中，下列何者錯誤?', '["人類於兒童早期（約3至5歲）就已經會表現出對於同種族成員的偏好", "人類於兒童早期（約3至5歲）就能分辨各種不同族群的文化差異", "人類於兒童早期（約3至5歲）大致已就能感知自己所屬的族群", "人類於兒童早期（約3至5歲）對自己族群認同的學習比對其他族群的識別早"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07065', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Werner Boehm所提出的社會功能觀點，係源自下列何種理論？', '["社會互動論", "生態系統論", "結構功能論", "社會發展論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07066', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者係屬於連續理論（continuity theory）的看法？', '["由於身體功能日衰，老人要持續慢慢淡出人際互動舞臺，才能維持平衡適應的狀態", "原本低度社會參與的，到了老年階段，較適合改成高度參與的生活；原本高度社會參與的，到了老年 階段，較適合改成低度參與的生活", "為彌補晚年生活內涵的失落，老人應持續維持積極活躍的社會參與，才能獲得較佳的生活品質", "人的生命歷程具有連續性也具可塑性，它是一種持續終生的歷程，老年階段也只是其中一環，欲獲得 較佳的老年適應，就必須先改善之前積累下來的風險因子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07067', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對家庭暴力的觀察，何者正確？', '["家庭暴力是短期的，受傷害者以男人及兒童為多", "家庭親密關係講求愛的諒解、包容、接納的力量，愛可化解一切家庭暴力危機", "家庭暴力因涉及隱私，傳統法不過家門、家醜不可外揚的觀念，往往導致受害者隱匿不報", "社會工作者只要有毅力，可獨當一面以專業解決家暴案例"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07068', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關性別主流化研究（Gender Mainstreaming Studies）的觀察，下列何者錯誤？', '["性別主流化研究是讓邊緣/弱勢群體具有發聲的正當性與合法性，而非受到主流的壓迫而成為看不見的 一群", "挑戰男性霸權文化建構的知識，具有批判性", "跨越所有人文與社會學門，具有包容性與延展性，不僅對各學科發生本質上的影響，更透過此整合各 學科之間的相關性", "性別主流化研究的起源與婦女運動息息相關，因此僅以改變女性主體性發展觀念為目標，並不涉及改 善深層制度與結構的社會實踐行動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07069', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '預期平均餘命（Life Expectancy）的定義為何？', '["是指人類長壽的極限", "是指在特定年份出生人口的平均歲數", "是指65歲以上老人人口的平均歲數", "是指65歲以上老人人口死亡的平均歲數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
